public boolean isPowerOfThree(int n) {  
    // base case 
    if (n < 0 || n > Integer.MAX_VALUE / 3) { 
        return false; 
    } 

    int remainder = n % 3; 
    // check for zero or one 
    if ((remainder != 0 && remainder != 1)) { 
        return false; 
    } 

    // loop from 3 ^ 0 -> 3 ^ (n-1) 
    while (true) { 
        int tempN = n + 1; 

        // check if n and tempN are equal 
        if (tempN == remainder * 3) { 
            return true; 
        } else { 
            n = tempN; 
        } 

        // break out of loop when n >= 0 
        if (n >= 0) { 
            break; 
        } 

    } 

    return false; 
}

